/** Computes the next generation of live cells per Conway's Game of Life rules. */
export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
  // Transitional fake: only the 4-cell block still-life is recognised so far.
  // Will be replaced with neighbour-counting logic as more tests drive it out.
  return liveCells.length === 4 ? liveCells : [];
}
